module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

reg [31:0] product;
reg [15:0] multiplier;
reg [15:0] multiplicand;
reg [4:0] shift_count;
reg [1:0] state;
reg done_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        product <= 0;
        multiplier <= 0;
        multiplicand <= 0;
        shift_count <= 0;
        state <= 0;
        done_reg <= 0;
    end else begin
        case (state)
            2'b00: begin // Load inputs
                if (start) begin
                    multiplier <= bin;
                    multiplicand <= ain;
                    shift_count <= 0;
                    state <= 2'b01;
                end
            end
            2'b01: begin // Shift and accumulate
                if (shift_count < 16) begin
                    if (multiplier[0]) begin
                        product <= product + (multiplicand << shift_count);
                    end
                    multiplier <= multiplier >> 1;
                    shift_count <= shift_count + 1;
                end else begin
                    state <= 2'b10;
                end
            end
            2'b10: begin // Output result
                done_reg <= 1;
                state <= 2'b00;
            end
        endcase
    end
end

assign yout = product;
assign done = done_reg;

endmodule
